public int minOperations(int[] nums, int start, int goal) {
    Set<Integer> seen = new HashSet<>();
    Queue<Integer> queue = new LinkedList<>();
    seen.add(start);
    queue.offer(start);
    int level = 0;

    while (!queue.isEmpty()) {
        int size = queue.size();
        for (int i = 0; i < size; i++) {
            int x = queue.poll();
            if (x == goal) return level;
            for (int num : nums) {
                int next = x + num;
                if (next >= 0 && next <= 1000 && !seen.contains(next)) {
                    seen.add(next);
                    queue.offer(next);
                }
            }
        }
        level++;
    }
    return -1;
}
